/* =========================================================
   RULES GLOSSARY DATA
   Content for the "Rules Glossary" dropdown in the Reference
   pane. Plain data only (title/body per entry) -- dm-screen.js
   reads this and builds the actual dropdown elements on page
   load via renderDataDrivenReferenceSections(), same pattern
   used for LORE_DATA and SPELLS_DATA.
   ========================================================= */

const RULES_GLOSSARY_DATA = {"intro": "", "entries": [{"id": "glossary-abbreviations", "title": "Abbreviations", "html": "<p><a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-armor-class\">AC</a> = <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-armor-class\">Armor Class</a> · C = <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-concentration\">Concentration</a> · CE = Chaotic Evil · CG = Chaotic Good · <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-charisma\">Cha.</a> = <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-charisma\">Charisma</a> · CN = Chaotic Neutral · Con. = Constitution · CP = Copper Piece(s) · <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-challenge-rating\">CR</a> = <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-challenge-rating\">Challenge Rating</a> · <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-difficulty-class\">DC</a> = <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-difficulty-class\">Difficulty Class</a> · <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-dexterity\">Dex.</a> = <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-dexterity\">Dexterity</a> · DM = Dungeon Master</p>\n                      <p>EP = Electrum Piece(s) · GP = Gold Piece(s) · <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-hit-points\">HP</a> = Hit Point(s) · <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-intelligence\">Int.</a> = <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-intelligence\">Intelligence</a> · LE = Lawful Evil · LG = Lawful Good · LN = Lawful Neutral · M = Material component · N = Neutral · NE = Neutral Evil · NG = Neutral Good · NPC = <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-npc\">Nonplayer character</a></p>\n                      <p>PB = <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-proficiency\">Proficiency</a> Bonus · PP = Platinum Piece(s) · R = <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-ritual\">Ritual</a> · S = Somatic component · SP = Silver Piece(s) · <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-strength\">Str.</a> = <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-strength\">Strength</a> · V = Verbal component · <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-wisdom\">Wis.</a> = <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-wisdom\">Wisdom</a> · <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-experience-points\">XP</a> = Experience Point(s)</p>"}, {"id": "glossary-ability-check", "title": "Ability Check", "html": "<p>A <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-d20-test\">D20 Test</a> that represents using one of the six abilities — or a specific <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-skill\">skill</a> associated with an ability — to overcome a challenge.</p>"}, {"id": "glossary-ability-score", "title": "Ability Score and Modifier", "html": "<p>A <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-creature\">creature</a> has six ability scores — <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-strength\">Strength</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-dexterity\">Dexterity</a>, Constitution, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-intelligence\">Intelligence</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-wisdom\">Wisdom</a>, and <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-charisma\">Charisma</a> — each with a corresponding modifier. Add the modifier when making a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-d20-test\">D20 Test</a> with that ability, or whenever a rule says to.</p>"}, {"id": "glossary-acrobatics", "title": "Acrobatics", "html": "<p>A <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-dexterity\">Dexterity</a> <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-skill\">skill</a> covering staying on your feet in a tricky situation, such as running across ice, balancing on a tightrope, or staying upright on a rocking ship's deck. It's also the check you make to perform acrobatic stunts, including dives, rolls, somersaults, and flips.</p>"}, {"id": "glossary-action", "title": "Action", "html": "<p>On your turn you can take one action. The special named actions (<a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-attack-action\">Attack</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-dash\">Dash</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-disengage\">Disengage</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-dodge\">Dodge</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-help\">Help</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-hide\">Hide</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-influence\">Influence</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-magic-action\">Magic</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-ready\">Ready</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-search\">Search</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-study\">Study</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-utilize\">Utilize</a>) each have their own entry below, in addition to whatever special actions your features provide.</p>"}, {"id": "glossary-advantage", "title": "Advantage", "html": "<p>If you have Advantage on a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-d20-test\">D20 Test</a>, roll two d20s and use the higher roll. A roll can't be affected by more than one Advantage, and Advantage and <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-disadvantage\">Disadvantage</a> on the same roll cancel each other out.</p>"}, {"id": "glossary-adventure", "title": "Adventure", "html": "<p>A series of <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-encounter\">encounters</a>. A story emerges through playing them.</p>"}, {"id": "glossary-alignment", "title": "Alignment", "html": "<p>A <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-creature\">creature</a>'s alignment broadly describes its ethical <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-attitude\">attitudes</a> and ideals: one factor identifies morality (good, evil, or neutral), the other describes attitude toward order (lawful, chaotic, or neutral) — nine possible combinations in total, such as Lawful Good or Neutral Evil.</p>"}, {"id": "glossary-ally", "title": "Ally", "html": "<p>A <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-creature\">creature</a> is your ally if it's a member of your adventuring party, your friend, on your side in combat, or designated as your ally by the rules or the DM.</p>"}, {"id": "glossary-animal-handling", "title": "Animal Handling", "html": "<p>A <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-wisdom\">Wisdom</a> <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-skill\">skill</a> used to calm a domesticated animal, keep a mount from bolting, or intuit an animal's intentions. The DM might also call for this check to control your mount when you attempt a risky maneuver.</p>"}, {"id": "glossary-arcana", "title": "Arcana", "html": "<p>An <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-intelligence\">Intelligence</a> <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-skill\">skill</a> measuring your ability to recall lore about spells, magic items, eldritch symbols, magical traditions, the planes of existence, and the inhabitants of those planes. See also the <a href=\"#\" class=\"gloss-ref\" data-ref=\"dropCreatureTypes\">Creature Types by Skill dropdown</a> above.</p>"}, {"id": "glossary-area-of-effect", "title": "Area of Effect", "html": "<p>Many <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-spell\">spells</a> and features have an area of effect, typically one of six shapes: <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-cone\">Cone</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-cube\">Cube</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-cylinder\">Cylinder</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-emanation\">Emanation</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-line\">Line</a>, or <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-sphere\">Sphere</a> (each has its own entry below).</p>\n                      <p>An area of effect has a point of origin, from which its energy erupts. If every straight line from the point of origin to a location in the area is blocked by an obstruction giving <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-total-cover\">Total Cover</a>, that location isn't included. If the origin point is placed unseen behind an obstruction such as a wall, the origin instead forms on the near side of it.</p>"}, {"id": "glossary-armor-class", "title": "Armor Class", "html": "<p>The <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-target\">target</a> number for an <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-attack-roll\">attack roll</a> — how difficult a target is to hit. Base AC is 10 plus your <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-dexterity\">Dexterity</a> modifier, unless a rule gives you another base AC calculation; you can only use one such calculation at a time.</p>"}, {"id": "glossary-armor-training", "title": "Armor Training", "html": "<p>Lets you use armor of a certain category without penalty. Wearing Light, Medium, or Heavy armor without training gives <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-disadvantage\">Disadvantage</a> on any <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-strength\">Strength</a> or <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-dexterity\">Dexterity</a> <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-d20-test\">D20 Test</a> and prevents casting <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-spell\">spells</a>. Using a <a href=\"#\" class=\"gloss-ref\" data-ref=\"spell-shield\">Shield</a> without training means you don't gain its <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-armor-class\">AC</a> bonus.</p>"}, {"id": "glossary-athletics", "title": "Athletics", "html": "<p>A <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-strength\">Strength</a> <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-skill\">skill</a> covering difficult situations while climbing, jumping, or swimming, such as pulling yourself over a ledge, jumping farther than normal, or avoiding hazards in rough water. It's also the check used to grapple or shove a creature in melee.</p>"}, {"id": "glossary-attack-action", "title": "Attack [Action]", "html": "<p>Lets you make one <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-attack-roll\">attack roll</a> with a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-weapon\">weapon</a> or an <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-unarmed-strike\">Unarmed Strike</a>.</p>\n                      <ul>\n                        <li><strong>Equipping/Unequipping.</strong> You can equip or unequip one weapon as part of this <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-action\">action</a>, before or after the attack, without needing to use it for that attack.</li>\n                        <li><strong>Moving Between Attacks.</strong> If a feature such as Extra Attack gives you more than one attack, you can split your movement between those attacks.</li>\n                      </ul>"}, {"id": "glossary-attack-roll", "title": "Attack Roll", "html": "<p>A <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-d20-test\">D20 Test</a> representing an <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-attack-action\">attack</a> with a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-weapon\">weapon</a>, an <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-unarmed-strike\">Unarmed Strike</a>, or a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-spell\">spell</a>.</p>"}, {"id": "glossary-attitude", "title": "Attitude", "html": "<p>A <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-monster\">monster</a>'s starting attitude toward a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-player-character\">player character</a>: <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-friendly\">Friendly</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-hostile\">Hostile</a>, or <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-indifferent\">Indifferent</a>.</p>"}, {"id": "glossary-attunement", "title": "Attunement", "html": "<p>Some <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-magic-action\">magic</a> items require forming a bond — Attunement — before their magical properties can be used. A <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-creature\">creature</a> can be attuned to no more than three magic items at a time.</p>"}, {"id": "glossary-blindsight", "title": "Blindsight", "html": "<p>Lets you see within a set range without relying on physical sight. You can see anything not behind <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-total-cover\">Total Cover</a> in that range even if <a href=\"#\" class=\"gloss-ref\" data-ref=\"condition-blinded\">Blinded</a> or in <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-darkness\">Darkness</a>, and you can see <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-creature\">creatures</a> with the <a href=\"#\" class=\"gloss-ref\" data-ref=\"condition-invisible\">Invisible</a> <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-condition\">condition</a> within that range.</p>"}, {"id": "glossary-bloodied", "title": "Bloodied", "html": "<p>A <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-creature\">creature</a> is Bloodied while it has half its <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-hit-points\">Hit Points</a> or fewer remaining.</p>"}, {"id": "glossary-bonus-action", "title": "Bonus Action", "html": "<p>A special <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-action\">action</a> you can take on the same turn as your action. You can't take more than one Bonus Action per turn, and only when a rule explicitly grants one.</p>"}, {"id": "glossary-breaking-objects", "title": "Breaking Objects", "html": "<p>The DM may allow an exceedingly fragile <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-object\">object</a> to be broken automatically with the <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-attack-action\">Attack</a> or <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-utilize\">Utilize</a> <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-action\">action</a>. Otherwise, use the tables below.</p>\n                      <table class=\"humanoid-grid\">\n                        <thead><tr><th><a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-armor-class\">AC</a></th><th>Substance</th></tr></thead>\n                        <tbody>\n                          <tr><td>11</td><td>Cloth, paper, rope</td></tr>\n                          <tr><td>13</td><td>Crystal, glass, ice</td></tr>\n                          <tr><td>15</td><td>Wood</td></tr>\n                          <tr><td>17</td><td>Stone</td></tr>\n                          <tr><td>19</td><td>Iron, steel</td></tr>\n                          <tr><td>21</td><td>Mithral</td></tr>\n                          <tr><td>23</td><td>Adamantine</td></tr>\n                        </tbody>\n                      </table>\n                      <table class=\"humanoid-grid\" style=\"margin-top:8px;\">\n                        <thead><tr><th><a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-size\">Size</a></th><th>Fragile</th><th>Resilient</th></tr></thead>\n                        <tbody>\n                          <tr><td>Tiny (bottle, lock)</td><td>2 (1d4)</td><td>5 (2d4)</td></tr>\n                          <tr><td>Small (chest, lute)</td><td>3 (1d6)</td><td>10 (3d6)</td></tr>\n                          <tr><td>Medium (barrel, chandelier)</td><td>4 (1d8)</td><td>18 (4d8)</td></tr>\n                          <tr><td>Large (cart, table)</td><td>5 (1d10)</td><td>27 (5d10)</td></tr>\n                        </tbody>\n                      </table>\n                      <p style=\"margin-top:8px;\">Objects have <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-immunity\">Immunity</a> to Poison and Psychic <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-damage\">damage</a>; the DM may rule other types more or less effective (e.g. paper/cloth Vulnerable to Fire). Big objects like walls may have a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-damage-threshold\">damage threshold</a>. An object without assigned ability scores can't make <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-ability-check\">ability checks</a> and fails all <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-saving-throw\">saving throws</a>.</p>"}, {"id": "glossary-bright-light", "title": "Bright Light", "html": "<p>Normal illumination.</p>"}, {"id": "glossary-burning", "title": "Burning [Hazard]", "html": "<p>A burning <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-creature\">creature</a> or <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-object\">object</a> takes 1d4 Fire <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-damage\">damage</a> at the start of each of its turns. As an <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-action\">action</a>, a creature can extinguish itself by dropping <a href=\"#\" class=\"gloss-ref\" data-ref=\"condition-prone\">Prone</a> and rolling on the ground. Fire also goes out if doused, submerged, or suffocated.</p>"}, {"id": "glossary-burrow-speed", "title": "Burrow Speed", "html": "<p>Lets a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-creature\">creature</a> move through sand, earth, mud, or ice. It can't burrow through solid rock unless a trait says otherwise.</p>"}, {"id": "glossary-campaign", "title": "Campaign", "html": "<p>A series of <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-adventure\">adventures</a>.</p>"}, {"id": "glossary-cantrip", "title": "Cantrip", "html": "<p>A level 0 <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-spell\">spell</a>, cast without using a spell slot.</p>"}, {"id": "glossary-carrying-capacity", "title": "Carrying Capacity", "html": "<p>Your <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-size\">size</a> and <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-strength\">Strength</a> score determine how much weight you can carry, drag, lift, or push. While dragging, lifting, or pushing more than you can carry, your <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-speed\">Speed</a> can be no more than 5 feet.</p>\n                      <table class=\"humanoid-grid\">\n                        <thead><tr><th>Size</th><th>Carry</th><th>Drag/Lift/Push</th></tr></thead>\n                        <tbody>\n                          <tr><td>Tiny</td><td><a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-strength\">Str.</a> × 7.5 lb.</td><td><a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-strength\">Str.</a> × 15 lb.</td></tr>\n                          <tr><td>Small/Medium</td><td><a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-strength\">Str.</a> × 15 lb.</td><td><a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-strength\">Str.</a> × 30 lb.</td></tr>\n                          <tr><td>Large</td><td><a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-strength\">Str.</a> × 30 lb.</td><td><a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-strength\">Str.</a> × 60 lb.</td></tr>\n                          <tr><td>Huge</td><td><a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-strength\">Str.</a> × 60 lb.</td><td><a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-strength\">Str.</a> × 120 lb.</td></tr>\n                          <tr><td>Gargantuan</td><td><a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-strength\">Str.</a> × 120 lb.</td><td><a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-strength\">Str.</a> × 240 lb.</td></tr>\n                        </tbody>\n                      </table>"}, {"id": "glossary-challenge-rating", "title": "Challenge Rating", "html": "<p>Summarizes the threat a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-monster\">monster</a> poses to four <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-player-character\">player characters</a>. Higher than party level suggests danger, lower suggests little threat — but circumstances and party <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-size\">size</a> can change this significantly in play.</p>"}, {"id": "glossary-character-sheet", "title": "Character Sheet", "html": "<p>A paper or digital record used to track your character's information.</p>"}, {"id": "glossary-charisma", "title": "Charisma", "html": "<p>One of the six <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-ability-score\">ability scores</a>. Charisma measures your ability to influence, entertain, or deceive others through force of personality. It governs the <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-deception\">Deception</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-intimidation\">Intimidation</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-performance\">Performance</a>, and <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-persuasion\">Persuasion</a> skills, and is the spellcasting ability for Bards, Paladins, Sorcerers, and Warlocks.</p>"}, {"id": "glossary-climbing", "title": "Climbing", "html": "<p>Each foot of movement while climbing costs 1 extra foot (2 extra in <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-difficult-terrain\">Difficult Terrain</a>) unless you have and use a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-climb-speed\">Climb Speed</a>. The DM may require a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-difficulty-class\">DC</a> 15 <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-strength\">Strength</a> (<a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-athletics\">Athletics</a>) check on a slippery surface or one with few handholds.</p>"}, {"id": "glossary-climb-speed", "title": "Climb Speed", "html": "<p>Used in place of <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-speed\">Speed</a> to climb a vertical surface without the extra movement cost normally required.</p>"}, {"id": "glossary-concentration", "title": "Concentration", "html": "<p>Some <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-spell\">spells</a> and effects require Concentration to stay active. It can be ended voluntarily at any time (no <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-action\">action</a>). It's broken by any of the following:</p>\n                      <ul>\n                        <li><strong>Another Concentration Effect.</strong> Starting to cast a Concentration spell, or activating another Concentration effect, ends the previous one.</li>\n                        <li><strong><a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-damage\">Damage</a>.</strong> Taking damage requires a Constitution save (<a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-difficulty-class\">DC</a> = 10 or half the damage taken, whichever is higher, max DC 30) to maintain it.</li>\n                        <li><strong><a href=\"#\" class=\"gloss-ref\" data-ref=\"condition-incapacitated\">Incapacitated</a> or <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-dead\">Dead</a>.</strong> Concentration ends immediately if you're <a href=\"#\" class=\"gloss-ref\" data-ref=\"condition-incapacitated\">Incapacitated</a> or die.</li>\n                      </ul>"}, {"id": "glossary-condition", "title": "Condition", "html": "<p>A temporary game state that affects its recipient in a defined way. A condition doesn't stack with itself — a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-creature\">creature</a> either has it or doesn't — except <a href=\"#\" class=\"gloss-ref\" data-ref=\"condition-exhaustion\">Exhaustion</a>, which is cumulative. See the <a href=\"#\" class=\"gloss-ref\" data-ref=\"dropConditions\">Conditions dropdown</a> above for the full list.</p>"}, {"id": "glossary-cone", "title": "Cone [Area of Effect]", "html": "<p>Extends in straight lines from a point of origin in a chosen direction. Its width at any point equals that point's distance from the origin (e.g. 15 feet wide at 15 feet from the origin). The origin itself isn't included in the area unless its creator says otherwise.</p>"}, {"id": "glossary-crawling", "title": "Crawling", "html": "<p>Each foot of movement while crawling costs 1 extra foot (2 extra in <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-difficult-terrain\">Difficult Terrain</a>).</p>"}, {"id": "glossary-creature", "title": "Creature", "html": "<p>Any being in the game, including a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-player-character\">player character</a>, is a creature.</p>"}, {"id": "glossary-creature-type", "title": "Creature Type", "html": "<p>Every <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-creature\">creature</a> has a tag identifying its type (most <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-player-character\">player characters</a> are <a href=\"#\" class=\"gloss-ref\" data-ref=\"creature-type-humanoid\">Humanoid</a>). Types have no rules of their own, but some rules affect certain types differently. See the <a href=\"#\" class=\"gloss-ref\" data-ref=\"dropCreatureTypes\">Creature Types by Skill dropdown</a> above.</p>"}, {"id": "glossary-critical-hit", "title": "Critical Hit", "html": "<p>Rolling a natural 20 on an <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-attack-roll\">attack roll</a> scores a Critical Hit, which always hits regardless of <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-armor-class\">AC</a> or modifiers. Roll all the <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-attack-action\">attack</a>'s <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-damage\">damage</a> dice twice and add them together, then add relevant modifiers.</p>"}, {"id": "glossary-cube", "title": "Cube [Area of Effect]", "html": "<p>Extends in straight lines from a point of origin located anywhere on one of its faces. The effect that creates it specifies the length of each side. The origin isn't included in the area unless its creator says otherwise.</p>"}, {"id": "glossary-curses", "title": "Curses", "html": "<p>The effect that confers a curse defines what it does. Curses can be removed by <a href=\"#\" class=\"gloss-ref\" data-ref=\"spell-remove-curse\">Remove Curse</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"spell-greater-restoration\">Greater Restoration</a>, or other <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-magic-action\">magic</a> that explicitly ends curses.</p>"}, {"id": "glossary-cylinder", "title": "Cylinder [Area of Effect]", "html": "<p>Extends in straight lines from a point of origin at the center of the circular top or bottom face. The effect specifies the base radius and the height. Unlike most shapes, the origin point IS included in the area.</p>"}, {"id": "glossary-d20-test", "title": "D20 Test", "html": "<p>Covers the three main d20 rolls: <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-ability-check\">ability checks</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-attack-roll\">attack rolls</a>, and <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-saving-throw\">saving throws</a>. Anything affecting D20 Tests affects all three. The DM decides when a D20 Test is warranted.</p>"}, {"id": "glossary-damage", "title": "Damage", "html": "<p>Represents harm that causes a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-creature\">creature</a> or <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-object\">object</a> to lose <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-hit-points\">Hit Points</a>.</p>"}, {"id": "glossary-damage-roll", "title": "Damage Roll", "html": "<p>A die roll, adjusted by applicable modifiers, that deals <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-damage\">damage</a> to a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-target\">target</a>.</p>"}, {"id": "glossary-damage-threshold", "title": "Damage Threshold", "html": "<p>A <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-creature\">creature</a> or <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-object\">object</a> with a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-damage\">damage</a> threshold has <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-immunity\">Immunity</a> to all damage unless a single <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-attack-action\">attack</a> or effect deals damage equal to or greater than the threshold, in which case it takes the full amount. Damage that fails to meet the threshold is superficial and does nothing.</p>"}, {"id": "glossary-damage-types", "title": "Damage Types", "html": "<p>Acid, Bludgeoning, Cold, Fire, Force, Lightning, Necrotic, Piercing, Poison, Psychic, Radiant, Slashing, Thunder. <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-damage\">Damage</a> types carry no rules of their own, but other rules (like <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-resistance\">Resistance</a>) key off them.</p>"}, {"id": "glossary-darkness", "title": "Darkness", "html": "<p>An area of Darkness is <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-heavily-obscured\">Heavily Obscured</a>.</p>"}, {"id": "glossary-darkvision", "title": "Darkvision", "html": "<p>Lets you see in <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-dim-light\">Dim Light</a> within a set range as if it were <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-bright-light\">Bright Light</a>, and in <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-darkness\">Darkness</a> within that range as if it were <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-dim-light\">Dim Light</a> (colors appear only as shades of gray in that Darkness).</p>"}, {"id": "glossary-dash", "title": "Dash [Action]", "html": "<p>Gives extra movement equal to your <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-speed\">Speed</a> (after modifiers) for the current turn. You may use a special speed (like <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-fly-speed\">Fly Speed</a>) instead of your normal Speed, chosen each time you Dash.</p>"}, {"id": "glossary-dead", "title": "Dead", "html": "<p>A dead <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-creature\">creature</a> has no <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-hit-points\">Hit Points</a> and can't regain them without <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-magic-action\">magic</a> like <a href=\"#\" class=\"gloss-ref\" data-ref=\"spell-raise-dead\">Raise Dead</a> or <a href=\"#\" class=\"gloss-ref\" data-ref=\"spell-revivify\">Revivify</a> — the spirit must consent, having departed for the <a href=\"#\" class=\"gloss-ref\" data-ref=\"lore-outer-planes\">Outer Planes</a>. On revival it keeps ongoing <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-condition\">conditions</a>, contagions, or <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-curses\">curses</a> (if durations haven't lapsed), returns with 1 fewer <a href=\"#\" class=\"gloss-ref\" data-ref=\"condition-exhaustion\">Exhaustion</a> level if it died with any, and loses any <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-attunement\">Attunement</a> it had.</p>"}, {"id": "glossary-death-saving-throw", "title": "Death Saving Throw", "html": "<p>A <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-player-character\">player character</a> must make a Death Save if they start their turn at 0 <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-hit-points\">Hit Points</a>.</p>"}, {"id": "glossary-deception", "title": "Deception", "html": "<p>A <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-charisma\">Charisma</a> <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-skill\">skill</a> used to convincingly hide the truth, whether verbally or through your actions — lying, fast-talking a guard, or wearing a disguise.</p>"}, {"id": "glossary-dehydration", "title": "Dehydration [Hazard]", "html": "<p>Drinking less than half a day's required water gives 1 <a href=\"#\" class=\"gloss-ref\" data-ref=\"condition-exhaustion\">Exhaustion</a> level at day's end, which can't be removed until a full day's water is drunk.</p>\n                      <table class=\"humanoid-grid\">\n                        <thead><tr><th><a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-size\">Size</a></th><th>Water/day</th></tr></thead>\n                        <tbody>\n                          <tr><td>Tiny</td><td>1/4 gallon</td></tr>\n                          <tr><td>Small</td><td>1 gallon</td></tr>\n                          <tr><td>Medium</td><td>1 gallon</td></tr>\n                          <tr><td>Large</td><td>4 gallons</td></tr>\n                          <tr><td>Huge</td><td>16 gallons</td></tr>\n                          <tr><td>Gargantuan</td><td>64 gallons</td></tr>\n                        </tbody>\n                      </table>"}, {"id": "glossary-dexterity", "title": "Dexterity", "html": "<p>One of the six <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-ability-score\">ability scores</a>. Dexterity measures agility, reflexes, and balance. It governs your base <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-armor-class\">Armor Class</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-initiative\">Initiative</a>, and the <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-acrobatics\">Acrobatics</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-sleight-of-hand\">Sleight of Hand</a>, and <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-stealth\">Stealth</a> skills, along with ranged and Finesse <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-weapon-attack\">weapon attacks</a>.</p>"}, {"id": "glossary-difficult-terrain", "title": "Difficult Terrain", "html": "<p>Every foot of movement in Difficult Terrain costs 1 extra foot (not cumulative — a space either is or isn't Difficult Terrain). A space qualifies if it contains, among other things: a non-Tiny non-<a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-ally\">ally</a> <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-creature\">creature</a>, furniture sized for your <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-size\">size</a> or larger, heavy snow/ice/rubble/undergrowth, liquid shin-to-waist deep, a narrow opening one size smaller than you, or a slope of 20 degrees or more.</p>"}, {"id": "glossary-difficulty-class", "title": "Difficulty Class", "html": "<p>The <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-target\">target</a> number (DC) for an <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-ability-check\">ability check</a> or <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-saving-throw\">saving throw</a>.</p>"}, {"id": "glossary-dim-light", "title": "Dim Light", "html": "<p>An area of Dim Light is <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-lightly-obscured\">Lightly Obscured</a>.</p>"}, {"id": "glossary-disadvantage", "title": "Disadvantage", "html": "<p>If you have Disadvantage on a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-d20-test\">D20 Test</a>, roll two d20s and use the lower roll. A roll can't be affected by more than one Disadvantage, and <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-advantage\">Advantage</a>/Disadvantage on the same roll cancel out.</p>"}, {"id": "glossary-disengage", "title": "Disengage [Action]", "html": "<p>Your movement doesn't provoke <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-opportunity-attacks\">Opportunity Attacks</a> for the rest of the turn.</p>"}, {"id": "glossary-dodge", "title": "Dodge [Action]", "html": "<p>Until the start of your next turn, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-attack-roll\">attack rolls</a> against you have <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-disadvantage\">Disadvantage</a> if you can see the attacker, and you make <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-dexterity\">Dexterity</a> saves with <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-advantage\">Advantage</a>. Lost if you're <a href=\"#\" class=\"gloss-ref\" data-ref=\"condition-incapacitated\">Incapacitated</a> or your <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-speed\">Speed</a> is 0.</p>"}, {"id": "glossary-emanation", "title": "Emanation [Area of Effect]", "html": "<p>Extends in straight lines from a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-creature\">creature</a> or <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-object\">object</a> in all directions, out to a distance the effect specifies. It moves with its origin unless instantaneous or stationary. The origin itself isn't included in the area unless its creator says otherwise.</p>"}, {"id": "glossary-encounter", "title": "Encounter", "html": "<p>A scene in an <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-adventure\">adventure</a> belonging to at least one of the game's three pillars: social interaction, exploration, or combat.</p>"}, {"id": "glossary-enemy", "title": "Enemy", "html": "<p>A <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-creature\">creature</a> is your enemy if it fights against you, actively works to harm you, or is designated your enemy by the rules or DM.</p>"}, {"id": "glossary-experience-points", "title": "Experience Points", "html": "<p>Awarded by the DM for overcoming challenges and completing <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-adventure\">adventures</a>. Crossing certain XP thresholds increases a character's level.</p>"}, {"id": "glossary-expertise", "title": "Expertise", "html": "<p>Doubles your <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-proficiency\">Proficiency</a> Bonus on an <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-ability-check\">ability check</a> using a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-skill\">skill</a> <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-proficiency\">proficiency</a> you have Expertise in (unless already doubled by another feature). Expertise is gained in a skill you're already proficient in, and can't stack twice in the same skill.</p>"}, {"id": "glossary-falling", "title": "Falling [Hazard]", "html": "<p>A fall deals 1d6 Bludgeoning <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-damage\">damage</a> at the end of the fall per 10 feet fallen, max 20d6, and leaves you <a href=\"#\" class=\"gloss-ref\" data-ref=\"condition-prone\">Prone</a> on landing unless you take no damage. Falling into liquid lets you use your <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-reaction\">Reaction</a> for a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-difficulty-class\">DC</a> 15 <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-strength\">Strength</a> (<a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-athletics\">Athletics</a>) or <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-dexterity\">Dexterity</a> (<a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-acrobatics\">Acrobatics</a>) check to hit head/feet first, halving the damage on a success.</p>"}, {"id": "glossary-flying", "title": "Flying", "html": "<p>While flying, you fall if <a href=\"#\" class=\"gloss-ref\" data-ref=\"condition-incapacitated\">Incapacitated</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"condition-prone\">Prone</a>, or your <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-fly-speed\">Fly Speed</a> drops to 0 — unless you can <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-hover\">hover</a>.</p>"}, {"id": "glossary-fly-speed", "title": "Fly Speed", "html": "<p>Lets you travel through the air. You can stay aloft until you land, fall, or die.</p>"}, {"id": "glossary-friendly", "title": "Friendly [Attitude]", "html": "<p>A Friendly <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-creature\">creature</a> views you favorably; you have <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-advantage\">Advantage</a> on <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-ability-check\">ability checks</a> to <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-influence\">influence</a> it.</p>"}, {"id": "glossary-grappling", "title": "Grappling", "html": "<p>Characters typically grapple with an <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-unarmed-strike\">Unarmed Strike</a>; some <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-monster\">monsters</a> have special grapple <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-attack-action\">attacks</a>.</p>\n                      <ul>\n                        <li><strong><a href=\"#\" class=\"gloss-ref\" data-ref=\"condition-grappled\">Grappled</a> <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-condition\">Condition</a>.</strong> A successful grapple gives the <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-target\">target</a> the <a href=\"#\" class=\"gloss-ref\" data-ref=\"condition-grappled\">Grappled</a> condition.</li>\n                        <li><strong>One Grapple per Hand.</strong> A free hand (or equivalent body part) is needed, and it can grapple only one <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-creature\">creature</a> at a time.</li>\n                        <li><strong>Ending a Grapple.</strong> The target can use its <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-action\">action</a> for a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-strength\">Strength</a> (<a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-athletics\">Athletics</a>) or <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-dexterity\">Dexterity</a> (<a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-acrobatics\">Acrobatics</a>) check against the escape <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-difficulty-class\">DC</a>. It also ends if the grappler is <a href=\"#\" class=\"gloss-ref\" data-ref=\"condition-incapacitated\">Incapacitated</a>, if the target is moved beyond the grapple's range, or if the grappler releases it (no action required).</li>\n                      </ul>"}, {"id": "glossary-half-cover", "title": "Half Cover", "html": "<p><strong>Half Cover</strong> = +2 <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-armor-class\">AC</a> and <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-dexterity\">Dexterity</a> <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-saving-throw\">Saving Throw</a></p><p>A target has half cover if an obstacle blocks at least half of its body. The obstacle might be a low wall, a large piece of furniture, a narrow tree trunk, or a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-creature\">creature</a>, whether that creature is an enemy or a friend.</p>"}, {"id": "glossary-hazard", "title": "Hazard", "html": "<p>An environmental danger — see <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-burning\">Burning</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-dehydration\">Dehydration</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-falling\">Falling</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-malnutrition\">Malnutrition</a>, and <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-suffocation\">Suffocation</a>.</p>"}, {"id": "glossary-healing", "title": "Healing", "html": "<p>How you regain <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-hit-points\">Hit Points</a>.</p>"}, {"id": "glossary-heavily-obscured", "title": "Heavily Obscured", "html": "<p>Heavy smoke/fog, thick foliage, complete <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-darkness\">darkness</a>, or <a href=\"#\" class=\"gloss-ref\" data-ref=\"condition-invisible\">invisibility</a> are things that can cause you to be heavily obscured.</p><p>You have the <a href=\"#\" class=\"gloss-ref\" data-ref=\"condition-blinded\">Blinded</a> <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-condition\">condition</a> while trying to see something in a Heavily Obscured space.</p>"}, {"id": "glossary-help", "title": "Help [Action]", "html": "<ul>\n                        <li><strong>Assist an <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-ability-check\">Ability Check</a>.</strong> Choose a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-skill\">skill</a>/tool <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-proficiency\">proficiency</a> and a nearby <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-ally\">ally</a>; they get <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-advantage\">Advantage</a> on the next check with that skill/tool before the start of your next turn. DM has final say on feasibility.</li>\n                        <li><strong>Assist an <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-attack-roll\">Attack Roll</a>.</strong> Distract an <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-enemy\">enemy</a> within 5 feet, giving an ally <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-advantage\">Advantage</a> on their next <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-attack-action\">attack</a> against it before the start of your next turn.</li>\n                      </ul>"}, {"id": "glossary-heroic-inspiration", "title": "Heroic Inspiration", "html": "<p>Can be expended to reroll any die immediately after rolling it (must use the new result). Gaining it while you already have it is lost unless given to a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-player-character\">player character</a> who lacks it.</p>"}, {"id": "glossary-hide", "title": "Hide [Action]", "html": "<p>Requires a successful <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-difficulty-class\">DC</a> 15 <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-dexterity\">Dexterity</a> (<a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-stealth\">Stealth</a>) check while <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-heavily-obscured\">Heavily Obscured</a> or behind <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-three-quarters-cover\">Three-Quarters</a>/<a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-total-cover\">Total Cover</a>, and out of any <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-enemy\">enemy</a>'s line of sight. On success, you have the <a href=\"#\" class=\"gloss-ref\" data-ref=\"condition-invisible\">Invisible</a> <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-condition\">condition</a> while hidden; the check total becomes the DC for others to find you via <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-wisdom\">Wisdom</a> (<a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-perception\">Perception</a>).</p>\n                      <p>Hiding ends immediately if you make a sound louder than a whisper, an enemy finds you, you make an <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-attack-roll\">attack roll</a>, or you cast a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-spell\">spell</a> with a Verbal component.</p>"}, {"id": "glossary-high-jump", "title": "High Jump", "html": "<p>Jump vertically 3 + <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-strength\">Strength</a> modifier feet (min 0) with a 10-foot running start; half that standing still. Each foot costs a foot of movement. You can <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-reach\">reach</a> half your height higher during the jump, for a total reach of the jump height plus 1.5x your height. See the <a href=\"#\" class=\"gloss-ref\" data-ref=\"dropJumping\">Jumping calculator dropdown</a> above for exact numbers.</p>"}, {"id": "glossary-history", "title": "History", "html": "<p>An <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-intelligence\">Intelligence</a> <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-skill\">skill</a> measuring your ability to recall lore about historical events, legendary people, ancient kingdoms, past disputes, and lost civilizations.</p>"}, {"id": "glossary-hit-point-dice", "title": "Hit Point Dice", "html": "<p><a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-help\">Help</a> determine a character's <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-hit-points\">HP</a> maximum. Most <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-monster\">monsters</a> have them too. Can be spent during a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-short-rest\">Short Rest</a> to regain HP.</p>"}, {"id": "glossary-hit-points", "title": "Hit Points", "html": "<p>A measure of how hard a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-creature\">creature</a> or <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-object\">object</a> is to kill or destroy. <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-damage\">Damage</a> reduces HP, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-healing\">healing</a> restores it, and it can never exceed the maximum or drop below 0.</p>"}, {"id": "glossary-hostile", "title": "Hostile [Attitude]", "html": "<p>A Hostile <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-creature\">creature</a> views you unfavorably; you have <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-disadvantage\">Disadvantage</a> on <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-ability-check\">ability checks</a> to <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-influence\">influence</a> it.</p>"}, {"id": "glossary-hover", "title": "Hover", "html": "<p>Some <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-creature\">creatures</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-spell\">spells</a>, or effects grant the ability to hover, which prevents <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-falling\">falling</a> while <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-flying\">flying</a> in certain circumstances.</p>"}, {"id": "glossary-illusions", "title": "Illusions", "html": "<p>The effect that creates an illusion defines what it does and which senses it deceives. An illusion is insubstantial and weightless but seems affected by its environment (casting shadows, echoing, etc.) unless stated otherwise.</p>"}, {"id": "glossary-immunity", "title": "Immunity", "html": "<p>If you have Immunity to a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-damage\">damage</a> type or <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-condition\">condition</a>, it doesn't affect you at all.</p>"}, {"id": "glossary-improvised-weapons", "title": "Improvised Weapons", "html": "<p>An <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-object\">object</a> wielded as a makeshift <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-weapon\">weapon</a> (broken glass, a table leg, etc.). A Simple/Martial weapon used contrary to its design (e.g. a ranged weapon in melee, or throwing a non-Thrown melee weapon) also counts as improvised.</p>\n                      <ul>\n                        <li><strong><a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-proficiency\">Proficiency</a>.</strong> No <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-proficiency\">Proficiency</a> Bonus applies.</li>\n                        <li><strong><a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-damage\">Damage</a>.</strong> 1d4 of a type the DM deems appropriate on a hit.</li>\n                        <li><strong>Range.</strong> If thrown: normal range 20 feet, long range 60 feet.</li>\n                        <li><strong>Weapon Equivalents.</strong> The DM may rule that an improvised weapon resembling a real one uses that weapon's rules.</li>\n                      </ul>"}, {"id": "glossary-indifferent", "title": "Indifferent [Attitude]", "html": "<p>An Indifferent <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-creature\">creature</a> has no desire to <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-help\">help</a> or hinder you — the default <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-attitude\">attitude</a> of a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-monster\">monster</a>.</p>"}, {"id": "glossary-influence", "title": "Influence [Action]", "html": "<p>Urge a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-monster\">monster</a> to do something. The DM decides whether the monster is Willing (no check, it complies its own way), Unwilling (no check, it refuses), or Hesitant (requires an <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-ability-check\">ability check</a>).</p>\n                      <p>For a Hesitant response, the <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-difficulty-class\">DC</a> is 15 or the monster's <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-intelligence\">Intelligence</a> score, whichever is higher. Success means it does as urged; failure means you must wait 24 hours (or DM-set duration) to try the same approach again.</p>\n                      <table class=\"humanoid-grid\">\n                        <thead><tr><th><a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-ability-check\">Ability Check</a></th><th>Interaction</th></tr></thead>\n                        <tbody>\n                          <tr><td><a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-charisma\">Cha.</a> (<a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-deception\">Deception</a>)</td><td>Deceiving a monster that understands you</td></tr>\n                          <tr><td><a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-charisma\">Cha.</a> (<a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-intimidation\">Intimidation</a>)</td><td>Intimidating a monster</td></tr>\n                          <tr><td><a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-charisma\">Cha.</a> (<a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-performance\">Performance</a>)</td><td>Amusing a monster</td></tr>\n                          <tr><td><a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-charisma\">Cha.</a> (<a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-persuasion\">Persuasion</a>)</td><td>Persuading a monster that understands you</td></tr>\n                          <tr><td><a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-wisdom\">Wis.</a> (<a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-animal-handling\">Animal Handling</a>)</td><td>Gently coaxing a <a href=\"#\" class=\"gloss-ref\" data-ref=\"creature-type-beast\">Beast</a> or <a href=\"#\" class=\"gloss-ref\" data-ref=\"creature-type-monstrosity\">Monstrosity</a></td></tr>\n                        </tbody>\n                      </table>"}, {"id": "glossary-initiative", "title": "Initiative", "html": "<p>Determines turn order in combat. A DM may instead use a fixed Initiative score of 10 + <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-dexterity\">Dexterity</a> modifier, +5 if <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-advantage\">Advantage</a> on Initiative rolls, -5 if <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-disadvantage\">Disadvantage</a>.</p>"}, {"id": "glossary-insight", "title": "Insight", "html": "<p>A <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-wisdom\">Wisdom</a> <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-skill\">skill</a> used to determine the true intentions of a creature, such as spotting a lie or predicting someone's next move, by reading body language, speech habits, and changes in mannerisms.</p>"}, {"id": "glossary-intelligence", "title": "Intelligence", "html": "<p>One of the six <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-ability-score\">ability scores</a>. Intelligence measures reasoning and memory. It governs the <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-arcana\">Arcana</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-history\">History</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-investigation\">Investigation</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-nature\">Nature</a>, and <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-religion\">Religion</a> skills, and is the spellcasting ability for Wizards.</p>"}, {"id": "glossary-intimidation", "title": "Intimidation", "html": "<p>A <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-charisma\">Charisma</a> <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-skill\">skill</a> used to influence someone through overt threats, hostile actions, and physical violence.</p>"}, {"id": "glossary-investigation", "title": "Investigation", "html": "<p>An <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-intelligence\">Intelligence</a> <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-skill\">skill</a> used to deduce information from clues — searching for and finding a hidden object, deducing the location of a hidden passage, discerning the weak point in a wall, or determining the reason a mechanism isn't working.</p>"}, {"id": "glossary-jumping", "title": "Jumping", "html": "<p>A jump is either a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-long-jump\">Long Jump</a> (horizontal) or a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-high-jump\">High Jump</a> (vertical) — see their own entries, or the <a href=\"#\" class=\"gloss-ref\" data-ref=\"dropJumping\">Jumping calculator dropdown</a> above.</p>"}, {"id": "glossary-knocking-out", "title": "Knocking Out a Creature", "html": "<p>When a melee <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-attack-action\">attack</a> would reduce a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-creature\">creature</a> to 0 <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-hit-points\">HP</a>, you can instead reduce it to 1 HP; it gains the <a href=\"#\" class=\"gloss-ref\" data-ref=\"condition-unconscious\">Unconscious</a> <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-condition\">condition</a> and starts a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-short-rest\">Short Rest</a>. It stays <a href=\"#\" class=\"gloss-ref\" data-ref=\"condition-unconscious\">Unconscious</a> until it regains HP or someone succeeds on a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-difficulty-class\">DC</a> 10 <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-wisdom\">Wisdom</a> (<a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-medicine\">Medicine</a>) check to administer first aid.</p>"}, {"id": "glossary-lightly-obscured", "title": "Lightly Obscured", "html": "<p><a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-dim-light\">Dim light</a>, light fog, light foliage, heavy rain/snow are examples of things that can cause you to be lightly obscured.</p><p><a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-disadvantage\">Disadvantage</a> on <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-wisdom\">Wisdom</a> (<a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-perception\">Perception</a>) checks to see something in a Lightly Obscured space.</p>"}, {"id": "glossary-line", "title": "Line [Area of Effect]", "html": "<p>Extends from a point of origin in a straight path, covering an area defined by its length and width. The origin isn't included unless its creator says otherwise.</p>"}, {"id": "glossary-long-jump", "title": "Long Jump", "html": "<p>Leap horizontally up to your <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-strength\">Strength</a> score in feet with a 10-foot running start; half that standing still. Each foot costs a foot of movement. See the <a href=\"#\" class=\"gloss-ref\" data-ref=\"dropJumping\">Jumping calculator dropdown</a> above for exact numbers.</p>\n                      <p>Landing in <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-difficult-terrain\">Difficult Terrain</a> requires a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-difficulty-class\">DC</a> 10 <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-dexterity\">Dexterity</a> (<a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-acrobatics\">Acrobatics</a>) check or you fall <a href=\"#\" class=\"gloss-ref\" data-ref=\"condition-prone\">Prone</a>. At the DM's option, clearing a low obstacle (no taller than a quarter of the jump distance) requires a DC 10 <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-strength\">Strength</a> (<a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-athletics\">Athletics</a>) check, or you hit it.</p>"}, {"id": "glossary-long-rest", "title": "Long Rest", "html": "<p>At least 8 hours of downtime with at least 6 hours of sleep and no more than 2 hours of light activity. You must have at least 1 <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-hit-points\">HP</a> to start one, and must wait 16 hours after finishing one before starting another.</p>\n                      <p><strong>Benefits:</strong> regain all HP and spent <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-hit-point-dice\">Hit Point Dice</a> (and any reduced HP maximum returns to normal), reduced ability scores are restored, <a href=\"#\" class=\"gloss-ref\" data-ref=\"condition-exhaustion\">Exhaustion</a> level decreases by 1, and any features that recharge on a Long Rest do so.</p>\n                      <p><strong>Interruptions:</strong> rolling <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-initiative\">Initiative</a>, casting a non-<a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-cantrip\">cantrip</a> <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-spell\">spell</a>, taking any <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-damage\">damage</a>, or an hour of exertion — each stops the rest. If at least 1 hour had passed, you gain a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-short-rest\">Short Rest</a>'s benefits instead. Resuming after an interruption adds 1 extra hour per interruption.</p>"}, {"id": "glossary-magic-action", "title": "Magic [Action]", "html": "<p>Cast a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-spell\">spell</a> with a casting time of an <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-action\">action</a>, or activate a feature/item that requires this action. Spells with a casting time of 1 minute or longer require taking the Magic action (with <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-concentration\">Concentration</a>) on every turn of casting; if <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-concentration\">Concentration</a> breaks, the spell fails without expending a slot.</p>"}, {"id": "glossary-magical-effect", "title": "Magical Effect", "html": "<p>An effect is magical if created by a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-spell\">spell</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-magic-action\">magic</a> item, or a phenomenon a rule labels magical.</p>"}, {"id": "glossary-malnutrition", "title": "Malnutrition [Hazard]", "html": "<p>Eating less than half a day's required food requires a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-difficulty-class\">DC</a> 10 Constitution save or gain 1 <a href=\"#\" class=\"gloss-ref\" data-ref=\"condition-exhaustion\">Exhaustion</a> level at day's end. Eating nothing for 5 days automatically gives 1 <a href=\"#\" class=\"gloss-ref\" data-ref=\"condition-exhaustion\">Exhaustion</a> level at day 5, plus another for each additional day without food. This Exhaustion can't be removed until a full day's food is eaten.</p>\n                      <table class=\"humanoid-grid\">\n                        <thead><tr><th><a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-size\">Size</a></th><th>Food/day</th></tr></thead>\n                        <tbody>\n                          <tr><td>Tiny</td><td>1/4 pound</td></tr>\n                          <tr><td>Small</td><td>1 pound</td></tr>\n                          <tr><td>Medium</td><td>1 pound</td></tr>\n                          <tr><td>Large</td><td>4 pounds</td></tr>\n                          <tr><td>Huge</td><td>16 pounds</td></tr>\n                          <tr><td>Gargantuan</td><td>64 pounds</td></tr>\n                        </tbody>\n                      </table>"}, {"id": "glossary-medicine", "title": "Medicine", "html": "<p>A <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-wisdom\">Wisdom</a> <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-skill\">skill</a> used to stabilize a dying creature, diagnose an illness, or recall knowledge of anatomy and physiology — such as identifying a creature's vulnerable points, determining the cause of an unusual wound, or recognizing the effects of a disease or poison already at work.</p>"}, {"id": "glossary-monster", "title": "Monster", "html": "<p>A <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-creature\">creature</a> controlled by the DM, even if benevolent.</p>"}, {"id": "glossary-nature", "title": "Nature", "html": "<p>An <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-intelligence\">Intelligence</a> <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-skill\">skill</a> measuring your ability to recall lore about terrain, plants, animals, and weather, along with certain <a href=\"#\" class=\"gloss-ref\" data-ref=\"dropCreatureTypes\">creature types</a>.</p>"}, {"id": "glossary-npc", "title": "Nonplayer Character", "html": "<p>An NPC is a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-monster\">monster</a> with a personal name and a distinct personality.</p>"}, {"id": "glossary-object", "title": "Object", "html": "<p>A nonliving, distinct thing. Composite things (like buildings) comprise more than one object.</p>"}, {"id": "glossary-occupied-space", "title": "Occupied Space", "html": "<p>A space is occupied if a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-creature\">creature</a> is in it, or it's completely filled by <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-object\">objects</a>.</p>"}, {"id": "glossary-opportunity-attacks", "title": "Opportunity Attacks", "html": "<p>Triggered when a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-creature\">creature</a> you can see leaves your <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-reach\">reach</a> via its <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-action\">action</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-bonus-action\">Bonus Action</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-reaction\">Reaction</a>, or a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-speed\">speed</a>. Use your Reaction to make one melee <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-attack-action\">attack</a> against it, occurring right before it leaves your reach.</p>"}, {"id": "glossary-passive-perception", "title": "Passive Perception", "html": "<p>Reflects general awareness without an active check: 10 + <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-wisdom\">Wisdom</a> (<a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-perception\">Perception</a>) check bonus, +5 with <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-advantage\">Advantage</a> on such checks, -5 with <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-disadvantage\">Disadvantage</a>.</p>"}, {"id": "glossary-per-day", "title": "Per Day", "html": "<p>A \"per day\" use requires finishing a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-long-rest\">Long Rest</a> to use again once exhausted.</p>"}, {"id": "glossary-perception", "title": "Perception", "html": "<p>A <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-wisdom\">Wisdom</a> <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-skill\">skill</a> used to spot, hear, or otherwise detect the presence of something — noticing something easy to miss or hearing a conversation through a closed door. See also <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-passive-perception\">Passive Perception</a>.</p>"}, {"id": "glossary-performance", "title": "Performance", "html": "<p>A <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-charisma\">Charisma</a> <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-skill\">skill</a> used to delight an audience with music, dance, acting, storytelling, or other forms of entertainment.</p>"}, {"id": "glossary-persuasion", "title": "Persuasion", "html": "<p>A <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-charisma\">Charisma</a> <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-skill\">skill</a> used to influence someone or a group with tact, social graces, or good nature — such as convincing a guard to let you pass, negotiating a price, or calming an agitated crowd.</p>"}, {"id": "glossary-player-character", "title": "Player Character", "html": "<p>A character controlled by a player.</p>"}, {"id": "glossary-possession", "title": "Possession", "html": "<p>A possessing effect defines how the possession works. Prevented by <a href=\"#\" class=\"gloss-ref\" data-ref=\"spell-protection-from-evil-and-good\">Protection from Evil and Good</a>, and ended by <a href=\"#\" class=\"gloss-ref\" data-ref=\"spell-dispel-good-and-evil\">Dispel Evil and Good</a>.</p>"}, {"id": "glossary-proficiency", "title": "Proficiency", "html": "<p>Add your Proficiency Bonus to a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-d20-test\">D20 Test</a> made with something you're proficient in — a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-skill\">skill</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-saving-throw\">saving throw</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-weapon\">weapon</a>, or tool.</p>"}, {"id": "glossary-reach", "title": "Reach", "html": "<p>A <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-creature\">creature</a> has 5 feet of reach unless a rule says otherwise.</p>"}, {"id": "glossary-reaction", "title": "Reaction", "html": "<p>A special <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-action\">action</a> taken in response to a defined trigger, usable on another <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-creature\">creature</a>'s turn (or your own, alongside an action/<a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-bonus-action\">Bonus Action</a>). Only one Reaction can be taken per round, resetting at the start of your next turn. The Opportunity <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-attack-action\">Attack</a> is a Reaction available to all creatures.</p>"}, {"id": "glossary-ready", "title": "Ready [Action]", "html": "<p>Wait for a specific circumstance before acting. On your turn, choose the trigger and the response (an <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-action\">action</a> or moving up to your <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-speed\">Speed</a>); when the trigger occurs, you may use your <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-reaction\">Reaction</a> to respond or ignore it.</p>\n                      <p>Readying a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-spell\">spell</a> (casting time of an action) expends its resources immediately but holds the effect, requiring <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-concentration\">Concentration</a> until released or until the start of your next turn — if <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-concentration\">Concentration</a> breaks, the spell fizzles with no effect.</p>"}, {"id": "glossary-religion", "title": "Religion", "html": "<p>An <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-intelligence\">Intelligence</a> <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-skill\">skill</a> measuring your ability to recall lore about deities, rites and prayers, religious hierarchies, holy symbols, and the practices of secret cults.</p>"}, {"id": "glossary-resistance", "title": "Resistance", "html": "<p><a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-damage\">Damage</a> of a type you have Resistance to is halved (<a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-round-down\">round down</a>), applied only once per instance of damage.</p>"}, {"id": "glossary-ritual", "title": "Ritual", "html": "<p>A prepared <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-spell\">spell</a> with the Ritual tag can be cast as a Ritual, taking 10 minutes longer but expending no spell slot — meaning it can't be cast at a higher level this way.</p>"}, {"id": "glossary-round-down", "title": "Round Down", "html": "<p>When dividing or multiplying, round down on a fraction — even exactly one-half — unless a rule specifically says to round up.</p>"}, {"id": "glossary-saving-throw", "title": "Saving Throw", "html": "<p>Also called a save — an attempt to avoid or resist a threat, made only when a rule requires it (though you may choose to fail without rolling). If a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-target\">target</a> lacks the required ability score, it automatically fails.</p>"}, {"id": "glossary-search", "title": "Search [Action]", "html": "<p>Make a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-wisdom\">Wisdom</a> check to discern something not obvious.</p>\n                      <table class=\"humanoid-grid\">\n                        <thead><tr><th><a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-skill\">Skill</a></th><th>Thing to Detect</th></tr></thead>\n                        <tbody>\n                          <tr><td><a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-insight\">Insight</a></td><td><a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-creature\">Creature</a>'s state of mind</td></tr>\n                          <tr><td><a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-medicine\">Medicine</a></td><td>Creature's ailment or cause of death</td></tr>\n                          <tr><td><a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-perception\">Perception</a></td><td>Concealed creature or <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-object\">object</a></td></tr>\n                          <tr><td><a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-survival\">Survival</a></td><td>Tracks or food</td></tr>\n                        </tbody>\n                      </table>"}, {"id": "glossary-shape-shifting", "title": "Shape-Shifting", "html": "<p>Effects like Wild Shape or <a href=\"#\" class=\"gloss-ref\" data-ref=\"spell-polymorph\">Polymorph</a> specify what happens to you. Ongoing effects (<a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-condition\">conditions</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-spell\">spells</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-curses\">curses</a>) normally carry over between forms unless stated otherwise. You revert to your true form if you die.</p>"}, {"id": "glossary-short-rest", "title": "Short Rest", "html": "<p>A 1-hour period of downtime doing nothing more strenuous than reading, talking, eating, or standing watch. Requires at least 1 <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-hit-points\">HP</a> to start.</p>\n                      <p><strong>Benefits:</strong> spend <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-hit-point-dice\">Hit Point Dice</a> to regain HP (roll the die + Constitution modifier per die, minimum 1 HP each), and any features that recharge on a Short Rest do so.</p>\n                      <p><strong>Interruptions:</strong> rolling <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-initiative\">Initiative</a>, casting a non-<a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-cantrip\">cantrip</a> <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-spell\">spell</a>, or taking <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-damage\">damage</a> — an interrupted Short Rest gives no benefits.</p>"}, {"id": "glossary-simultaneous-effects", "title": "Simultaneous Effects", "html": "<p>If multiple things happen at once on a turn, whoever's turn it is (player or DM) decides the order.</p>"}, {"id": "glossary-size", "title": "Size", "html": "<p>Tiny, Small, Medium, Large, Huge, or Gargantuan. A <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-creature\">creature</a>'s size determines the space it occupies in combat; an <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-object\">object</a>'s size affects its <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-hit-points\">Hit Points</a>.</p>"}, {"id": "glossary-skill", "title": "Skill", "html": "<p>A specialization tied to an <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-ability-check\">ability check</a>. <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-proficiency\">Proficiency</a> in a skill adds your <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-proficiency\">Proficiency</a> Bonus to associated checks.</p>"}, {"id": "glossary-sleight-of-hand", "title": "Sleight of Hand", "html": "<p>A <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-dexterity\">Dexterity</a> <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-skill\">skill</a> used whenever you attempt an act of manual trickery, such as planting something on someone, palming an object, or picking a pocket or lock.</p>"}, {"id": "glossary-speed", "title": "Speed", "html": "<p>The distance in feet a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-creature\">creature</a> can move on its turn.</p>\n                      <p><strong>Special Speeds.</strong> <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-burrow-speed\">Burrow</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-climb-speed\">Climb</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-fly-speed\">Fly</a>, and <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-swim-speed\">Swim Speed</a> each have their own entry. With more than one, choose which to use as you move, switching mid-move by subtracting distance already moved from the new speed (if 0 or less, that speed can't be used this move).</p>\n                      <p><strong>Changes to Speed.</strong> If Speed is increased/decreased, any special speed changes by the same amount for the same duration (e.g. Speed reduced to 0 also reduces <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-climb-speed\">Climb Speed</a> to 0; Speed halved also halves <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-fly-speed\">Fly Speed</a>).</p>"}, {"id": "glossary-spell", "title": "Spell", "html": "<p>A <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-magical-effect\">magical effect</a> with the characteristics described under Spells in the rules.</p>"}, {"id": "glossary-spell-attack", "title": "Spell Attack", "html": "<p>An <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-attack-roll\">attack roll</a> made as part of a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-spell\">spell</a> or other <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-magical-effect\">magical effect</a>.</p>"}, {"id": "glossary-spellcasting-focus", "title": "Spellcasting Focus", "html": "<p>An <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-object\">object</a> certain <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-creature\">creatures</a> can use in place of a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-spell\">spell</a>'s Material components, provided those materials aren't consumed and have no listed cost.</p>"}, {"id": "glossary-sphere", "title": "Sphere [Area of Effect]", "html": "<p>Extends in straight lines from a point of origin outward in all directions, out to a specified radius. Unlike most shapes, the origin point IS included in the area.</p>"}, {"id": "glossary-stable", "title": "Stable", "html": "<p>A <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-creature\">creature</a> at 0 <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-hit-points\">HP</a> that isn't required to make Death <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-saving-throw\">Saving Throws</a>.</p>"}, {"id": "glossary-stat-block", "title": "Stat Block", "html": "<p>Contains a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-monster\">monster</a>'s game statistics: <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-size\">Size</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-creature-type\">Creature Type</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-alignment\">Alignment</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-armor-class\">AC</a>/<a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-initiative\">Initiative</a>/<a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-hit-points\">HP</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-speed\">Speed</a>, ability scores, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-skill\">skills</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-resistance\">resistances</a>/<a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-vulnerability\">vulnerabilities</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-immunity\">immunities</a>, gear, senses, languages, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-challenge-rating\">CR</a> (with <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-experience-points\">XP</a> and <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-proficiency\">Proficiency</a> Bonus), and its traits, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-action\">actions</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-bonus-action\">bonus actions</a>, and <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-reaction\">reactions</a>.</p>\n                      <p><a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-attack-action\">Attack</a> entries give whether it's melee or ranged, the attack bonus, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-reach\">reach</a>/range, and effect on a hit. Save-based effects give the save type, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-difficulty-class\">DC</a>, who must save, and the effects of failure/success. <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-damage\">Damage</a> is usually shown as both a static number and a die expression (e.g. \"4 (1d4 + 2)\") — the DM picks one, not both.</p>"}, {"id": "glossary-stealth", "title": "Stealth", "html": "<p>A <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-dexterity\">Dexterity</a> <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-skill\">skill</a> used when you try to conceal yourself, slip past guards, sneak up on someone, or approach without being seen or heard. See also the <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-hide\">Hide</a> action.</p>"}, {"id": "glossary-strength", "title": "Strength", "html": "<p>One of the six <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-ability-score\">ability scores</a>. Strength measures physical power. It governs the <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-athletics\">Athletics</a> skill, most melee <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-weapon-attack\">weapon attacks</a>, and your <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-carrying-capacity\">Carrying Capacity</a>.</p>"}, {"id": "glossary-study", "title": "Study [Action]", "html": "<p>Make an <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-intelligence\">Intelligence</a> check to recall an important piece of information from memory, a book, a clue, or another source.</p>\n                      <table class=\"humanoid-grid\">\n                        <thead><tr><th><a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-skill\">Skill</a></th><th>Areas</th></tr></thead>\n                        <tbody>\n                          <tr><td><a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-arcana\">Arcana</a></td><td><a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-spell\">Spells</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-magic-action\">magic</a> items, planes, and <a href=\"#\" class=\"gloss-ref\" data-ref=\"creature-type-aberration\">Aberrations</a>/<a href=\"#\" class=\"gloss-ref\" data-ref=\"creature-type-construct\">Constructs</a>/<a href=\"#\" class=\"gloss-ref\" data-ref=\"creature-type-elemental\">Elementals</a>/<a href=\"#\" class=\"gloss-ref\" data-ref=\"creature-type-fey\">Fey</a>/<a href=\"#\" class=\"gloss-ref\" data-ref=\"creature-type-monstrosity\">Monstrosities</a></td></tr>\n                          <tr><td><a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-history\">History</a></td><td>Historic events, civilizations, wars, and <a href=\"#\" class=\"gloss-ref\" data-ref=\"creature-type-giant\">Giants</a>/<a href=\"#\" class=\"gloss-ref\" data-ref=\"creature-type-humanoid\">Humanoids</a></td></tr>\n                          <tr><td><a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-investigation\">Investigation</a></td><td>Traps, ciphers, riddles, gadgetry</td></tr>\n                          <tr><td><a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-nature\">Nature</a></td><td>Terrain, flora, weather, and <a href=\"#\" class=\"gloss-ref\" data-ref=\"creature-type-beast\">Beasts</a>/<a href=\"#\" class=\"gloss-ref\" data-ref=\"creature-type-dragon\">Dragons</a>/<a href=\"#\" class=\"gloss-ref\" data-ref=\"creature-type-ooze\">Oozes</a>/<a href=\"#\" class=\"gloss-ref\" data-ref=\"creature-type-plant\">Plants</a></td></tr>\n                          <tr><td><a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-religion\">Religion</a></td><td>Deities, rites, holy symbols, cults, and <a href=\"#\" class=\"gloss-ref\" data-ref=\"creature-type-celestial\">Celestials</a>/<a href=\"#\" class=\"gloss-ref\" data-ref=\"creature-type-fiend\">Fiends</a>/<a href=\"#\" class=\"gloss-ref\" data-ref=\"creature-type-undead\">Undead</a></td></tr>\n                        </tbody>\n                      </table>"}, {"id": "glossary-suffocation", "title": "Suffocation [Hazard]", "html": "<p>A <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-creature\">creature</a> can hold its breath for 1 + Constitution modifier minutes (minimum 30 seconds). Once out of breath or choking, it gains 1 <a href=\"#\" class=\"gloss-ref\" data-ref=\"condition-exhaustion\">Exhaustion</a> level at the end of each of its turns until it can breathe again, at which point all levels gained this way are removed.</p>"}, {"id": "glossary-surprise", "title": "Surprise", "html": "<p>A <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-creature\">creature</a> caught unawares at the start of combat is surprised, giving it <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-disadvantage\">Disadvantage</a> on its <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-initiative\">Initiative</a> roll.</p>"}, {"id": "glossary-survival", "title": "Survival", "html": "<p>A <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-wisdom\">Wisdom</a> <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-skill\">skill</a> used to follow tracks, hunt wild game, guide a group through frozen wastelands, identify signs of a coming storm, or avoid natural hazards.</p>"}, {"id": "glossary-swimming", "title": "Swimming", "html": "<p>Each foot of movement while swimming costs 1 extra foot (2 extra in <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-difficult-terrain\">Difficult Terrain</a>) unless you have and use a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-swim-speed\">Swim Speed</a>. The DM may require a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-difficulty-class\">DC</a> 15 <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-strength\">Strength</a> (<a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-athletics\">Athletics</a>) check to move any distance in rough water.</p>"}, {"id": "glossary-swim-speed", "title": "Swim Speed", "html": "<p>Lets you swim without the extra movement cost normally required.</p>"}, {"id": "glossary-target", "title": "Target", "html": "<p>A <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-creature\">creature</a> or <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-object\">object</a> targeted by an <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-attack-roll\">attack roll</a>, forced to save by an effect, or selected to receive a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-spell\">spell</a>'s or other phenomenon's effects.</p>"}, {"id": "glossary-telepathy", "title": "Telepathy", "html": "<p>Lets a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-creature\">creature</a> communicate mentally with another within range; the contacted creature needn't share a language but must understand at least one language or be telepathic itself.</p>\n                      <p>A telepath needn't see the <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-target\">target</a> and can start/end contact freely (no <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-action\">action</a>). Contact can't start, and is broken, if either party is <a href=\"#\" class=\"gloss-ref\" data-ref=\"condition-incapacitated\">Incapacitated</a>, if the target leaves range, or if the telepath contacts someone else. A non-telepath can receive but not initiate telepathic messages, though it can reply once contact is established.</p>"}, {"id": "glossary-teleportation", "title": "Teleportation", "html": "<p>You disappear and reappear elsewhere instantly without moving through the intervening space; this doesn't use movement (unless stated otherwise) and never provokes <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-opportunity-attacks\">Opportunity Attacks</a>. All worn/carried equipment teleports with you; a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-creature\">creature</a> you're merely touching doesn't, unless the effect says so. If the destination is occupied or blocked, you appear in the nearest <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-unoccupied-space\">unoccupied space</a> of your choice instead.</p>"}, {"id": "glossary-temporary-hp", "title": "Temporary Hit Points", "html": "<p>Granted by certain effects; act as a buffer against losing real <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-hit-points\">Hit Points</a>.</p>"}, {"id": "glossary-three-quarters-cover", "title": "Three-Quarters Cover", "html": "<p><strong>Three-Quarters Cover</strong> = +5 <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-armor-class\">AC</a> and <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-dexterity\">Dexterity</a> <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-saving-throw\">Saving Throw</a></p><p>A target has three-quarters cover if about three-quarters of it is covered by an obstacle. The obstacle might be a portcullis, an arrow slit, or a thick tree trunk.</p>"}, {"id": "glossary-total-cover", "title": "Total Cover", "html": "<p><strong>Total Cover</strong> = Can't be targeted directly</p><p>A target has total cover if it is completely concealed by an obstacle. For example, if the target is standing behind a wall or boulder.</p>"}, {"id": "glossary-tremorsense", "title": "Tremorsense", "html": "<p>Pinpoints <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-creature\">creatures</a>/moving <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-object\">objects</a> within range while both you and the <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-target\">target</a> share contact with the same surface or liquid. Can't detect anything airborne, and doesn't count as sight.</p>"}, {"id": "glossary-truesight", "title": "Truesight", "html": "<p>Within its range: see through normal and magical <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-darkness\">Darkness</a>, see <a href=\"#\" class=\"gloss-ref\" data-ref=\"condition-invisible\">Invisible</a> <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-creature\">creatures</a>/<a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-object\">objects</a>, see through visual <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-illusions\">illusions</a> (auto-succeeding saves against them), see a transformed creature's or object's true form, and see into the <a href=\"#\" class=\"gloss-ref\" data-ref=\"plane-ethereal\">Ethereal Plane</a>.</p>"}, {"id": "glossary-unarmed-strike", "title": "Unarmed Strike", "html": "<p>A punch, kick, headbutt, or similar blow — a melee <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-attack-action\">attack</a> against a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-target\">target</a> within 5 feet. Choose one effect:</p>\n                      <ul>\n                        <li><strong><a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-damage\">Damage</a>.</strong> <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-attack-roll\">Attack roll</a> (<a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-strength\">Strength</a> modifier + <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-proficiency\">Proficiency</a> Bonus); on a hit, 1 + <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-strength\">Strength</a> modifier Bludgeoning damage.</li>\n                        <li><strong>Grapple.</strong> Target makes a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-strength\">Strength</a> or <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-dexterity\">Dexterity</a> save (its choice) vs. <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-difficulty-class\">DC</a> 8 + <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-strength\">Strength</a> modifier + <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-proficiency\">Proficiency</a> Bonus, or gains the <a href=\"#\" class=\"gloss-ref\" data-ref=\"condition-grappled\">Grappled</a> <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-condition\">condition</a>. Only works on a target up to one <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-size\">size</a> larger, with a free hand.</li>\n                        <li><strong>Shove.</strong> Same DC and save; on a failure you push the target 5 feet away or knock it <a href=\"#\" class=\"gloss-ref\" data-ref=\"condition-prone\">Prone</a>. Only works on a target up to one size larger.</li>\n                      </ul>"}, {"id": "glossary-unoccupied-space", "title": "Unoccupied Space", "html": "<p>A space is unoccupied if no <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-creature\">creature</a> is in it and it isn't completely filled by <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-object\">objects</a>.</p>"}, {"id": "glossary-utilize", "title": "Utilize [Action]", "html": "<p>Used when interacting with an <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-object\">object</a> requires an <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-action\">action</a> on its own, rather than as part of another action (like drawing a sword as part of the <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-attack-action\">Attack</a> action).</p>"}, {"id": "glossary-vulnerability", "title": "Vulnerability", "html": "<p><a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-damage\">Damage</a> of a type you're Vulnerable to is doubled, applied only once per instance of damage.</p>"}, {"id": "glossary-weapon", "title": "Weapon", "html": "<p>An <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-object\">object</a> in the Simple or Martial weapon category.</p>"}, {"id": "glossary-weapon-attack", "title": "Weapon Attack", "html": "<p>An <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-attack-roll\">attack roll</a> made with a <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-weapon\">weapon</a>.</p>"}, {"id": "glossary-wisdom", "title": "Wisdom", "html": "<p>One of the six <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-ability-score\">ability scores</a>. Wisdom measures how attuned you are to your surroundings and to your own inner self. It governs the <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-animal-handling\">Animal Handling</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-insight\">Insight</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-medicine\">Medicine</a>, <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-perception\">Perception</a>, and <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-survival\">Survival</a> skills, your <a href=\"#\" class=\"gloss-ref\" data-ref=\"glossary-passive-perception\">Passive Perception</a>, and is the spellcasting ability for Clerics and Druids.</p>"}]};
